mapper.select:
SELECT tab.id, tab.orderNo, tab.welfareCenterRewardType, tab.receiveStatus, tab.currencyCode, tab.amount, tab.detailType, tab.pfTime, tab.pfEndTime FROM (
SELECT id, order_no as orderNo, 1 AS welfareCenterRewardType, CASE WHEN receive_status = 0 AND receive_end_time < #{vo.systemTime} THEN 2 ELSE receive_status END AS receiveStatus, currency_code AS currencyCode, activity_amount AS amount, activity_template AS detailType, CASE WHEN receive_status = 0 AND receive_end_time < #{vo.systemTime} or receive_status = 2 THEN receive_end_time WHEN receive_status = 1 THEN receive_time ELSE created_time END AS pfTime, receive_end_time AS pfEndTime FROM site_activity_order_record WHERE user_account = #{vo.userAccount} AND site_code = #{vo.siteCode} AND created_time >= #{vo.siteStartTime} and show_flag = 1
UNION ALL SELECT id, order_id as orderNo, 0 AS welfareCenterRewardType, CASE WHEN receive_status = 0 AND expired_time < #{vo.systemTime} THEN 2 ELSE receive_status END AS receiveStatus,
currency AS currencyCode, award_amount AS amount, award_type AS detailType, IF ( receive_status = 1, receive_time, record_start_time ) AS pfTime, expired_time AS pfEndTime FROM site_vip_award_record WHERE site_code = #{vo.siteCode} AND user_account = #{vo.userAccount} AND record_start_time >= #{vo.siteStartTime}
UNION ALL SELECT id, order_no as orderNo, 2 AS welfareCenterRewardType, receive_status AS receiveStatus, currency_code AS currencyCode, task_amount AS amount, sub_task_type AS detailType, IF ( receive_status = 1, receive_time, receive_start_time ) AS pfTime, receive_end_time AS pfEndTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} and task_type = 'novice' AND user_account = #{vo.userAccount} AND receive_start_time >= #{vo.siteStartTime}
UNION ALL SELECT id, order_no as orderNo, 5 AS welfareCenterRewardType, receive_status AS receiveStatus, currency_code AS currencyCode, task_amount AS amount, sub_task_type AS detailType, IF ( receive_status = 1, receive_time, receive_start_time ) AS pfTime, receive_end_time AS pfEndTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} and task_type = 'daily' AND user_account = #{vo.userAccount} AND receive_start_time >= #{vo.siteStartTime}
UNION ALL SELECT id, order_no as orderNo, 6 AS welfareCenterRewardType, receive_status AS receiveStatus, currency_code AS currencyCode, task_amount AS amount, sub_task_type AS detailType, IF ( receive_status = 1, receive_time, receive_start_time ) AS pfTime, receive_end_time AS pfEndTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} and task_type = 'week' AND user_account = #{vo.userAccount} AND receive_start_time >= #{vo.siteStartTime}
UNION ALL SELECT id, order_no as orderNo, 3 AS welfareCenterRewardType, open_status AS receiveStatus, 'WTC' AS currencyCode, reward_amount AS amount, 'LOOKUP_11642' AS detailType, IF ( open_status = 1, open_time, complete_time ) AS pfTime, NULL AS pfEndTime FROM medal_reward_record WHERE site_code = #{vo.siteCode} AND user_account = #{vo.userAccount} AND open_status = 1 AND complete_time >= #{vo.siteStartTime}
UNION ALL SELECT id, order_no as orderNo, 4 AS welfareCenterRewardType, lock_status AS receiveStatus, 'WTC' AS currencyCode, reward_amount AS amount, medal_name_i18 AS detailType, IF ( lock_status = 1, unlock_time, complete_time ) AS pfTime, unlock_time AS pfEndTime FROM medal_acquire_record WHERE site_code = #{vo.siteCode} AND user_account = #{vo.userAccount} and lock_status = 1 AND complete_time >= #{vo.siteStartTime}
UNION ALL SELECT id, order_no as orderNo, 7 AS welfareCenterRewardType, CASE WHEN open_status = 0 AND invalid_time < #{vo.systemTime} THEN 2 ELSE open_status END AS receiveStatus, 'WTC' AS currencyCode, reward_amount AS amount, 'LOOKUP_11608' AS detailType, IF ( open_status = 1, reward_time, updated_time ) AS pfTime, invalid_time AS pfEndTime FROM site_rebate_reward_record WHERE user_id =#{vo.userId} AND created_time >= #{vo.siteStartTime}
) tab
and tab.welfareCenterRewardType = #{vo.welfareCenterRewardType}
and tab.receiveStatus = #{vo.receiveStatus}
AND tab.pfTime BETWEEN #{vo.pfTimeStartTime} AND #{vo.pfTimeEndTime}
ORDER BY receiveStatus ASC, pfTime DESC

