UNION ALL SELECT id, order_no as orderNo, 7 AS welfareCenterRewardType, CASE WHEN open_status = 0 AND invalid_time < #{vo.systemTime} THEN 2 ELSE open_status END AS receiveStatus, 'WTC' AS currencyCode, reward_amount AS amount, 'LOOKUP_11608' AS detailType, IF ( open_status = 1, reward_time, updated_time ) AS pfTime, invalid_time AS pfEndTime FROM site_rebate_reward_record WHERE user_id =#{vo.userId} AND created_time >= #{vo.siteStartTime}
