UNION ALL SELECT id, order_no as orderNo, 2 AS welfareCenterRewardType, receive_status AS receiveStatus, currency_code AS currencyCode, task_amount AS amount, sub_task_type AS detailType, IF ( receive_status = 1, receive_time, receive_start_time ) AS pfTime, receive_end_time AS pfEndTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} AND user_account = #{vo.userAccount} and task_type = 'novice'
